// Direct sync trigger — called from frontend
// event.mode = 'INCREMENTAL' | 'FULL'
// event.token = Movidesk API token
// event.lastSync = last sync date (ISO string)
// event.startDate = optional start date filter
// event.pageSize = tickets per page (default 50)
// event.maxPages = max pages to fetch (safety limit)

const MOVIDESK_URL = 'https://api.movidesk.com/public/v1';
const mode = (event.mode || 'INCREMENTAL').toUpperCase();
const token = event.token || '';
const lastSync = event.lastSync || '';
const startDate = event.startDate || '';
const pageSize = parseInt(event.pageSize) || 50;
const maxPages = parseInt(event.maxPages) || 200;
const session = 'S' + Date.now().toString(36).toUpperCase();

if (!token) {
  return { success: false, error: 'Token Movidesk nao configurado', session };
}

const selectFields = 'id,protocol,type,subject,category,urgency,status,baseStatus,origin,createdDate,ownerTeam,serviceFirstLevel,lastUpdate,actionCount,lifeTimeWorkingTime,resolvedIn,closedIn,canceledIn,lastActionDate,slaAgreement,slaAgreementRule,slaSolutionTime,slaResponseTime';

const results = [];
let totalTickets = 0;
let totalErrors = 0;
let currentEndpoint = '';

async function fetchPage(endpoint, orderBy, filterParam, label, page) {
  const skip = page * pageSize;
  const url = MOVIDESK_URL + '/' + endpoint + '?token=' + token + '&$top=' + pageSize + '&$skip=' + skip + '&$select=' + selectFields + '&$orderby=' + orderBy + (filterParam || '');

  // Mask token in logged URL
  const logUrl = url.replace(token, token.substring(0, 4) + '****' + token.substring(token.length - 4));

  const start = Date.now();
  let responseCode = 0;
  let responseBody = '';
  let ticketsCount = 0;
  let error = '';

  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(120000) });
    responseCode = res.status;
    const elapsed = Date.now() - start;

    if (res.status === 429) {
      const retryAfter = parseInt(res.headers.get('retry-after') || '60');
      error = 'Rate limit (429). Retry-After: ' + retryAfter + 's';
      responseBody = 'Rate limited. Aguardar ' + retryAfter + 's antes de tentar novamente.';
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: false, retryAfter, tickets: [] };
    }

    if (res.status === 403) {
      const body = await res.text();
      error = 'HTTP 403 Forbidden — token invalido ou sem permissao';
      responseBody = body.substring(0, 500);
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: false, fatal: true, tickets: [] };
    }

    if (!res.ok) {
      const body = await res.text();
      error = 'HTTP ' + res.status;
      responseBody = body.substring(0, 500);
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: false, tickets: [] };
    }

    const tickets = await res.json();
    if (!Array.isArray(tickets)) {
      error = 'Resposta nao e array';
      responseBody = JSON.stringify(tickets).substring(0, 500);
      results.push({ page, label, responseCode, ticketsCount: 0, error, elapsed });
      return { ok: true, tickets: [] };
    }

    ticketsCount = tickets.length;
    responseBody = 'OK: ' + ticketsCount + ' tickets retornados';
    results.push({ page, label, responseCode, ticketsCount, error: '', elapsed });

    return { ok: true, tickets };
  } catch (e) {
    error = String(e.message || e).substring(0, 300);
    results.push({ page, label, responseCode: 0, ticketsCount: 0, error, elapsed: Date.now() - start });
    return { ok: false, tickets: [] };
  }
}

// Determine sync strategy
const isFullSync = mode === 'FULL' || !lastSync;
let filterParam = '';

if (!isFullSync && lastSync) {
  // Incremental: filter by lastUpdate > lastSync - 2min
  const d = new Date(lastSync);
  d.setMinutes(d.getMinutes() - 2);
  filterParam = '&$filter=lastUpdate ge ' + d.toISOString().slice(0, 19) + 'z';
} else if (startDate) {
  filterParam = '&$filter=lastUpdate ge ' + startDate + 'T00:00:00z';
}

// Fetch tickets
const endpoints = isFullSync
  ? [
      { endpoint: 'tickets/past', orderBy: 'id asc', label: 'FULL_PAST' },
      { endpoint: 'tickets', orderBy: 'lastUpdate asc', label: 'FULL_RECENT' }
    ]
  : [
      { endpoint: 'tickets', orderBy: 'lastUpdate asc', label: 'INCREMENTAL' }
    ];

let fatalError = false;
const ticketIds = [];

for (const ep of endpoints) {
  if (fatalError) break;
  currentEndpoint = ep.endpoint;

  for (let page = 0; page < maxPages; page++) {
    const result = await fetchPage(ep.endpoint, ep.orderBy, filterParam, ep.label, page);

    if (result.fatal) {
      fatalError = true;
      totalErrors++;
      break;
    }

    if (result.retryAfter) {
      // We can't wait long in a SF — return partial results
      totalErrors++;
      break;
    }

    if (!result.ok) {
      totalErrors++;
      if (totalErrors >= 3) break;
      continue;
    }

    if (result.tickets.length === 0) break;

    totalTickets += result.tickets.length;
    for (const t of result.tickets) {
      ticketIds.push(t.id);
    }

    if (result.tickets.length < pageSize) break;

    // Delay between pages to respect rate limit (6s = 10 req/min)
    await new Promise(r => setTimeout(r, 6500));
  }
}

return {
  success: !fatalError,
  session,
  mode: isFullSync ? 'FULL' : 'INCREMENTAL',
  totalTickets,
  totalErrors,
  totalRequests: results.length,
  endpoint: currentEndpoint,
  requests: results,
  ticketIdsSample: ticketIds.slice(0, 20),
  filterParam: filterParam || '(none)',
  message: fatalError
    ? 'Sync falhou com erro fatal (verifique token e permissoes)'
    : (totalTickets > 0 ? totalTickets + ' tickets encontrados' : 'Nenhum ticket novo encontrado')
};
